mapper.select:
SELECT a.id, a.title, a.content, a.publisher_id, a.deleted, a.created_at, a.updated_at, u.real_name AS publisher_name FROM announcements a JOIN users u ON a.publisher_id = u.id WHERE a.deleted = 0
AND (a.title LIKE CONCAT('%', #{keyword}, '%') OR a.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY a.created_at DESC, a.id DESC LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE announcements
SET title = #{title},
    content = #{content}
WHERE id = #{id}
  AND deleted = 0
